"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useState, useEffect, useCallback } from "react";
import Header from "@/components/Header";
import Button from "@/components/Button";

export default function AdminProfilePage() {
  const { status } = useSession();
  const router = useRouter();
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [successMessage, setSuccessMessage] = useState("");
  const [errorMessage, setErrorMessage] = useState("");

  const [profileData, setProfileData] = useState({
    email: "",
    role: "",
    profileImageUrl: "",
  });

  const [passwordForm, setPasswordForm] = useState({
    currentPassword: "",
    newPassword: "",
    confirmPassword: "",
  });

  const fetchProfile = useCallback(async () => {
    try {
      const response = await fetch("/api/admin/profile");
      if (response.ok) {
        const data = await response.json();
        setProfileData(data);
      } else {
        setErrorMessage("Failed to load profile data");
      }
    } catch (error) {
      console.error("Profile fetch error:", error);
      setErrorMessage("Failed to load profile data");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/login");
      return;
    }

    if (status === "authenticated") {
      Promise.resolve().then(() => {
        fetchProfile();
      });
    }
  }, [status, router, fetchProfile]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        setProfileData((prev) => ({
          ...prev,
          profileImageUrl: base64,
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handlePasswordChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setPasswordForm((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handlePasswordSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    setSuccessMessage("");
    setErrorMessage("");

    try {
      const response = await fetch("/api/admin/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...passwordForm,
          profileImage: profileData.profileImageUrl.startsWith("data:") ? profileData.profileImageUrl : null,
        }),
      });

      if (response.ok) {
        setSuccessMessage("Password changed successfully");
        setPasswordForm({
          currentPassword: "",
          newPassword: "",
          confirmPassword: "",
        });
        setTimeout(() => setSuccessMessage(""), 3000);
      } else {
        const data = await response.json();
        setErrorMessage(data.error || "Failed to change password");
      }
    } catch (error) {
      console.error("Password update error:", error);
      setErrorMessage("Failed to change password");
    } finally {
      setSubmitting(false);
    }
  };

  if (status === "loading" || loading) {
    return (
      <div className="min-h-screen bg-cream dark:bg-charcoal flex items-center justify-center">
        <div className="text-charcoal dark:text-cream">Loading...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-cream dark:bg-charcoal flex flex-col">
      <Header isAdmin={true} />
      <main className="flex-1 flex items-center justify-center px-4 py-12">
        <div className="w-full max-w-2xl space-y-6">
          {successMessage && (
            <div className="p-4 rounded-xl bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-100">
              {successMessage}
            </div>
          )}

          {errorMessage && (
            <div className="p-4 rounded-xl bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-100">
              {errorMessage}
            </div>
          )}

          {/* Profile Image Section */}
          <div className="mb-8 flex flex-col items-center gap-4">
            <div className="w-24 h-24 rounded-full bg-terracotta/10 dark:bg-gold/10 border-2 border-terracotta/20 dark:border-gold/20 flex items-center justify-center overflow-hidden">
              {profileData.profileImageUrl && profileData.profileImageUrl.startsWith("data:") ? (
                <img src={profileData.profileImageUrl} alt="Profile" className="w-full h-full object-cover" />
              ) : profileData.profileImageUrl ? (
                <img src={profileData.profileImageUrl} alt="Profile" className="w-full h-full object-cover" />
              ) : (
                <svg className="w-12 h-12 text-terracotta/40 dark:text-gold/40" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm0 3c1.66 0 3 1.34 3 3s-1.34 3-3 3-3-1.34-3-3 1.34-3 3-3zm0 14.2c-2.5 0-4.71-1.28-6-3.22.03-1.99 4-3.08 6-3.08 1.99 0 5.97 1.09 6 3.08-1.29 1.94-3.5 3.22-6 3.22z" />
                </svg>
              )}
            </div>
            <label className="px-4 py-2 rounded-lg bg-terracotta/10 dark:bg-gold/10 text-terracotta dark:text-gold font-semibold text-sm cursor-pointer hover:bg-terracotta/20 dark:hover:bg-gold/20 transition-colors">
              Change Photo
              <input
                type="file"
                accept="image/*"
                onChange={handleImageChange}
                className="hidden"
              />
            </label>
          </div>

          {/* Account Information Card */}
          <div className="bg-cream border border-terracotta/10 rounded-2xl p-6 sm:p-8 shadow-md dark:bg-charcoal dark:border-terracotta/20">
            <h2 className="text-2xl font-serif font-bold text-charcoal dark:text-cream mb-6">
              Account Information
            </h2>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-charcoal/70 dark:text-cream/70 mb-2">
                  Email
                </label>
                <input
                  type="email"
                  value={profileData.email}
                  disabled
                  className="w-full px-4 py-3 rounded-xl border border-terracotta/10 bg-terracotta/5 dark:bg-gold/5 text-charcoal dark:text-cream/70 cursor-not-allowed"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-charcoal/70 dark:text-cream/70 mb-2">
                  Role
                </label>
                <div className="flex items-center gap-2">
                  <div
                    className={`px-4 py-2 rounded-full text-xs font-bold text-white ${
                      profileData.role === "SUPER_ADMIN"
                        ? "bg-terracotta"
                        : "bg-gold text-charcoal"
                    }`}
                  >
                    {profileData.role}
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Change Password Card */}
          <div className="bg-cream border border-terracotta/10 rounded-2xl p-6 sm:p-8 shadow-md dark:bg-charcoal dark:border-terracotta/20">
            <h2 className="text-2xl font-serif font-bold text-charcoal dark:text-cream mb-6">
              Change Password
            </h2>

            <form onSubmit={handlePasswordSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-charcoal dark:text-cream mb-2">
                  Current Password
                </label>
                <input
                  type="password"
                  name="currentPassword"
                  value={passwordForm.currentPassword}
                  onChange={handlePasswordChange}
                  className="w-full px-4 py-3 rounded-xl border border-terracotta/20 dark:border-terracotta/40 bg-white dark:bg-charcoal/50 text-charcoal dark:text-cream placeholder:text-charcoal/40 dark:placeholder:text-cream/40 focus:outline-none focus:border-terracotta dark:focus:border-gold transition-colors"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-charcoal dark:text-cream mb-2">
                  New Password
                </label>
                <input
                  type="password"
                  name="newPassword"
                  value={passwordForm.newPassword}
                  onChange={handlePasswordChange}
                  className="w-full px-4 py-3 rounded-xl border border-terracotta/20 dark:border-terracotta/40 bg-white dark:bg-charcoal/50 text-charcoal dark:text-cream placeholder:text-charcoal/40 dark:placeholder:text-cream/40 focus:outline-none focus:border-terracotta dark:focus:border-gold transition-colors"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-charcoal dark:text-cream mb-2">
                  Confirm Password
                </label>
                <input
                  type="password"
                  name="confirmPassword"
                  value={passwordForm.confirmPassword}
                  onChange={handlePasswordChange}
                  className="w-full px-4 py-3 rounded-xl border border-terracotta/20 dark:border-terracotta/40 bg-white dark:bg-charcoal/50 text-charcoal dark:text-cream placeholder:text-charcoal/40 dark:placeholder:text-cream/40 focus:outline-none focus:border-terracotta dark:focus:border-gold transition-colors"
                />
              </div>

              <Button
                type="submit"
                disabled={submitting}
                variant="primary"
                size="lg"
                className="w-full"
                isLoading={submitting}
              >
                {submitting ? "Updating..." : "Update Password"}
              </Button>
            </form>
          </div>
        </div>
      </main>
    </div>
  );
}

import { NextResponse } from "next/server";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/db";

export async function GET() {
  try {
    const session = await getServerSession(authOptions);
    if (!session || !session.user) {
      return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    const role = (session.user as any).role;
    if (role !== "SUPER_ADMIN" && role !== "MODERATOR") {
      return NextResponse.json({ error: "Forbidden access: Admins only" }, { status: 403 });
    }

    // 1. Core counters
    const activeContestsCount = await prisma.competition.count({
      where: { isActive: true },
    });

    const pendingJudgingCount = await prisma.judgeAssignment.count({
      where: { isSubmitted: false },
    });

    const startOfToday = new Date();
    startOfToday.setHours(0, 0, 0, 0);
    const videosPostedTodayCount = await prisma.registration.count({
      where: {
        createdAt: {
          gte: startOfToday,
        },
      },
    });

    const pendingPaymentsCount = await prisma.registration.count({
      where: { paymentStatus: "PENDING" },
    });

    const certificatesCount = await prisma.certificate.count();

    const courierPendingCount = await prisma.registration.count({
      where: {
        scoringFinalized: true,
        certificate: null,
      },
    });

    // 2. 7-Day Revenue Intake
    const sevenDaysAgo = new Date();
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
    sevenDaysAgo.setHours(0, 0, 0, 0);

    const successfulTransactions = await prisma.transaction.findMany({
      where: {
        status: "SUCCESS",
        createdAt: {
          gte: sevenDaysAgo,
        },
      },
      select: {
        amount: true,
        createdAt: true,
      },
    });

    // Initialize daily revenue map
    const daysOfWeek = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];
    const dailyRevenue: { [key: string]: number } = {};
    
    // Fill last 7 days with 0
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setDate(d.getDate() - i);
      const dayName = daysOfWeek[d.getDay()];
      dailyRevenue[dayName] = 0;
    }

    successfulTransactions.forEach((tx) => {
      const dayName = daysOfWeek[new Date(tx.createdAt).getDay()];
      if (dailyRevenue[dayName] !== undefined) {
        dailyRevenue[dayName] += Number(tx.amount);
      }
    });

    const revenueData = Object.keys(dailyRevenue).map((day) => ({
      day,
      amount: dailyRevenue[day],
    }));

    const totalRevenueSum = successfulTransactions.reduce((acc, curr) => acc + Number(curr.amount), 0);

    // 3. Hotspots grouping
    const stateGroupings = await prisma.parent.groupBy({
      by: ["state"],
      _count: {
        id: true,
      },
      orderBy: {
        _count: {
          id: "desc",
        },
      },
      take: 4,
    });

    const totalParents = await prisma.parent.count();
    const hotspots = stateGroupings.map((g) => {
      const count = g._count.id;
      const pct = totalParents > 0 ? Math.round((count / totalParents) * 100) : 0;
      return {
        state: g.state || "Other",
        count,
        percentage: pct,
      };
    });

    // 4. Today's Urgent operations
    const endedCompetitions = await prisma.competition.findMany({
      where: {
        endDate: {
          lt: new Date(),
        },
      },
      take: 3,
      select: {
        title: true,
      },
    });

    const pendingAssignmentsByJudge = await prisma.judgeAssignment.groupBy({
      by: ["judgeId"],
      where: { isSubmitted: false },
      _count: {
        id: true,
      },
    });

    const judgesList = await prisma.judge.findMany({
      where: {
        id: {
          in: pendingAssignmentsByJudge.map((pa) => pa.judgeId),
        },
      },
      select: {
        id: true,
        name: true,
      },
    });

    const urgentJudges = judgesList.map((j) => {
      const pCount = pendingAssignmentsByJudge.find((pa) => pa.judgeId === j.id)?._count.id || 0;
      return {
        name: j.name,
        pendingCount: pCount,
      };
    }).filter(j => j.pendingCount > 0);

    return NextResponse.json({
      metrics: {
        activeContests: activeContestsCount,
        pendingJudging: pendingJudgingCount,
        videosPostedToday: videosPostedTodayCount,
        pendingPayments: pendingPaymentsCount,
        certificatesGenerated: certificatesCount,
        courierPending: courierPendingCount,
      },
      revenue: {
        totalLast7Days: totalRevenueSum,
        daily: revenueData,
      },
      hotspots,
      operations: {
        endedCompetitions: endedCompetitions.map(c => c.title),
        urgentJudges: urgentJudges.slice(0, 3),
      },
    });
  } catch (error: any) {
    console.error("Admin metrics fetch error:", error);
    return NextResponse.json({ error: "Internal server error occurred" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import prisma from "@/lib/db";
import { authOptions } from "@/lib/auth";
import { DeliveryStatus } from "@prisma/client";

/**
 * GET /api/admin/notifications/telegram/delivery-status
 * Retrieve Telegram message delivery statistics and records
 * Query params:
 *   - status: filter by delivery status (QUEUED, SENDING, SENT, TEMPORARILY_FAILED, PERMANENTLY_FAILED)
 *   - chatId: filter by specific chat ID
 *   - limit: pagination limit (default: 50, max: 500)
 *   - offset: pagination offset (default: 0)
 *   - sortBy: sort field (createdAt, sentAt, failureCount) (default: createdAt)
 *   - sortOrder: asc or desc (default: desc)
 */
export async function GET(request: NextRequest) {
  const session = await getServerSession(authOptions);

  if (!session?.user?.email) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const user = await prisma.user.findUnique({
    where: { email: session.user.email },
  });

  if (!user || (user.role !== "SUPER_ADMIN" && user.role !== "MODERATOR")) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  try {
    const { searchParams } = new URL(request.url);
    const status = searchParams.get("status") as DeliveryStatus | null;
    const chatId = searchParams.get("chatId");
    const limit = Math.min(
      parseInt(searchParams.get("limit") || "50"),
      500
    );
    const offset = parseInt(searchParams.get("offset") || "0");
    const sortBy = searchParams.get("sortBy") || "createdAt";
    const sortOrder = searchParams.get("sortOrder") || "desc";

    // Build where clause
    const where: any = {};
    if (status) {
      where.status = status;
    }
    if (chatId) {
      where.chatId = { contains: chatId };
    }

    // Get total count
    const totalCount = await prisma.telegramMessageDelivery.count({ where });

    // Get deliveries
    const deliveries = await prisma.telegramMessageDelivery.findMany({
      where,
      include: {
        notification: {
          select: {
            id: true,
            type: true,
            title: true,
            body: true,
            userId: true,
            createdAt: true,
          },
        },
      },
      take: limit,
      skip: offset,
      orderBy: { [sortBy]: sortOrder },
    });

    // Calculate statistics
    const stats = await prisma.telegramMessageDelivery.groupBy({
      by: ["status"],
      where,
      _count: true,
    });

    const statusCounts = {
      QUEUED: 0,
      SENDING: 0,
      SENT: 0,
      TEMPORARILY_FAILED: 0,
      PERMANENTLY_FAILED: 0,
    };

    stats.forEach((stat) => {
      statusCounts[stat.status as keyof typeof statusCounts] = stat._count;
    });

    // Calculate delivery rate
    const sentCount =
      statusCounts.SENT +
      statusCounts.TEMPORARILY_FAILED +
      statusCounts.PERMANENTLY_FAILED;
    const deliveryRate =
      sentCount > 0 ? ((statusCounts.SENT / sentCount) * 100).toFixed(2) : "0";

    return NextResponse.json({
      success: true,
      data: {
        pagination: {
          limit,
          offset,
          total: totalCount,
          pages: Math.ceil(totalCount / limit),
        },
        statistics: {
          statusCounts,
          deliveryRate: `${deliveryRate}%`,
          totalProcessed: sentCount,
        },
        deliveries: deliveries.map((d) => ({
          id: d.id,
          notificationId: d.notificationId,
          chatId: d.chatId,
          messageId: d.messageId,
          status: d.status,
          errorType: d.errorType,
          errorCode: d.errorCode,
          errorMessage: d.errorMessage,
          failureCount: d.failureCount,
          sentAt: d.sentAt,
          lastAttemptAt: d.lastAttemptAt,
          nextRetryAt: d.nextRetryAt,
          createdAt: d.createdAt,
          updatedAt: d.updatedAt,
          notification: d.notification,
        })),
      },
      timestamp: new Date().toISOString(),
    });
  } catch (error) {
    console.error("Error fetching delivery status:", error);
    return NextResponse.json(
      { error: "Failed to fetch delivery status" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import prisma from "@/lib/db";
import { authOptions } from "@/lib/auth";
import { sendTelegramWithTracking } from "@/lib/notifications";
import { DeliveryStatus } from "@prisma/client";

/**
 * POST /api/admin/notifications/telegram/retry
 * Retry failed Telegram deliveries
 * Query params:
 *   - deliveryId: specific delivery to retry
 *   - limit: number of failed deliveries to retry (default: 10)
 */
export async function POST(request: NextRequest) {
  const session = await getServerSession(authOptions);

  if (!session?.user?.email) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const user = await prisma.user.findUnique({
    where: { email: session.user.email },
  });

  if (!user || (user.role !== "SUPER_ADMIN" && user.role !== "MODERATOR")) {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  try {
    const { searchParams } = new URL(request.url);
    const deliveryId = searchParams.get("deliveryId");
    const limit = parseInt(searchParams.get("limit") || "10");

    let deliveriesToRetry;

    if (deliveryId) {
      // Retry specific delivery
      deliveriesToRetry = await prisma.telegramMessageDelivery.findMany({
        where: { id: deliveryId },
        include: { notification: true },
      });
    } else {
      // Retry failed deliveries that are due for retry
      deliveriesToRetry = await prisma.telegramMessageDelivery.findMany({
        where: {
          status: DeliveryStatus.TEMPORARILY_FAILED,
          nextRetryAt: { lte: new Date() },
        },
        take: limit,
        include: { notification: true },
        orderBy: { nextRetryAt: "asc" },
      });
    }

    const results = {
      attempted: 0,
      succeeded: 0,
      failed: 0,
      details: [] as any[],
    };

    for (const delivery of deliveriesToRetry) {
      results.attempted++;

      try {
        // Get the message content from notification
        const notification = delivery.notification;
        const message = `<b>${notification.title}</b>\n\n${notification.body}`;

        // Attempt to send
        await sendTelegramWithTracking(
          notification.id,
          delivery.chatId,
          message
        );

        results.succeeded++;
        results.details.push({
          deliveryId: delivery.id,
          status: "succeeded",
          chatId: delivery.chatId,
        });
      } catch (error) {
        results.failed++;
        results.details.push({
          deliveryId: delivery.id,
          status: "failed",
          chatId: delivery.chatId,
          error: error instanceof Error ? error.message : "Unknown error",
        });
      }
    }

    return NextResponse.json({
      success: true,
      results,
      timestamp: new Date().toISOString(),
    });
  } catch (error) {
    console.error("Error retrying Telegram deliveries:", error);
    return NextResponse.json(
      { error: "Failed to retry deliveries" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/db";

const ADMIN_ROLES = ["SUPER_ADMIN", "MODERATOR"];

// POST /api/admin/prizes/publish — publish a prize pool (locks it from editing)
export async function POST(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    if (!ADMIN_ROLES.includes((session.user as any).role)) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

    const body = await request.json();
    const { prizePoolId } = body;

    if (!prizePoolId) return NextResponse.json({ error: "prizePoolId is required" }, { status: 400 });

    const pool = await prisma.prizePool.findUnique({
      where: { id: prizePoolId },
      include: { items: true },
    });

    if (!pool) return NextResponse.json({ error: "Prize pool not found" }, { status: 404 });
    if (pool.isPublished) return NextResponse.json({ error: "Prize pool is already published" }, { status: 409 });

    // Validate: must have at least FIRST_PLACE and PARTICIPATION items
    const ranks = pool.items.map((i) => i.rank);
    if (!ranks.includes("FIRST_PLACE")) {
      return NextResponse.json({ error: "Prize pool must include a FIRST_PLACE prize before publishing" }, { status: 400 });
    }
    if (!ranks.includes("PARTICIPATION")) {
      return NextResponse.json({ error: "Prize pool must include a PARTICIPATION prize before publishing" }, { status: 400 });
    }

    const updated = await prisma.prizePool.update({
      where: { id: prizePoolId },
      data: { isPublished: true },
    });

    return NextResponse.json({ message: "Prize pool published successfully", prizePoolId: updated.id });
  } catch (error: any) {
    console.error("Prize pool publish error:", error);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/db";

const ADMIN_ROLES = ["SUPER_ADMIN", "MODERATOR"];

// GET /api/admin/prizes — all prize pools with items
export async function GET() {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    if (!ADMIN_ROLES.includes((session.user as any).role)) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

    const prizePools = await prisma.prizePool.findMany({
      include: {
        competition: { select: { id: true, title: true, scope: true } },
        items: {
          include: {
            awards: { select: { id: true, registrationId: true, rank: true, isDispatched: true } },
          },
          orderBy: { createdAt: "asc" },
        },
      },
      orderBy: { createdAt: "desc" },
    });

    const formatted = prizePools.map((pool) => ({
      id: pool.id,
      competitionId: pool.competitionId,
      competitionTitle: pool.competition.title,
      competitionScope: pool.competition.scope,
