// POST /api/admin/qualifications — create a qualification rule
export async function POST(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session?.user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    if (!ADMIN_ROLES.includes((session.user as any).role)) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

    const body = await request.json();
    const {
      stateCompetitionId,
      nationalCompetitionId,
      slotsPerCategory = 3,
      wildCardSlots = 1,
      minScoreThreshold,
      discountPercent = 50,
      slotExpiryDays = 14,
    } = body;

    if (!stateCompetitionId || !nationalCompetitionId) {
      return NextResponse.json({ error: "Both stateCompetitionId and nationalCompetitionId are required" }, { status: 400 });
    }

    const [stateComp, nationalComp] = await Promise.all([
      prisma.competition.findUnique({ where: { id: stateCompetitionId }, select: { scope: true, resultDate: true } }),
      prisma.competition.findUnique({ where: { id: nationalCompetitionId }, select: { scope: true, registrationDeadline: true } }),
    ]);

    if (!stateComp || stateComp.scope !== "STATE") {
      return NextResponse.json({ error: "stateCompetitionId must reference a STATE-scope competition" }, { status: 400 });
    }
    if (!nationalComp || nationalComp.scope !== "NATIONAL") {
      return NextResponse.json({ error: "nationalCompetitionId must reference a NATIONAL-scope competition" }, { status: 400 });
    }
    if (stateComp.resultDate >= nationalComp.registrationDeadline) {
      return NextResponse.json({
        error: "State competition result date must be before national competition registration deadline",
      }, { status: 400 });
    }

    const rule = await prisma.qualificationRule.create({
      data: {
        stateCompetitionId,
        nationalCompetitionId,
        slotsPerCategory,
        wildCardSlots,
        minScoreThreshold: minScoreThreshold ? parseFloat(minScoreThreshold) : null,
        discountPercent,
        slotExpiryDays,
        isActive: true,
      },
    });

    return NextResponse.json({ message: "Qualification rule created", rule: { id: rule.id } });
  } catch (error: any) {
    console.error("Qualifications POST error:", error);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/db";
import { createAndDispatchNotification } from "@/lib/notificationService";

export async function GET(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session || !session.user) {
      return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    const role = (session.user as any).role;
    if (role !== "SUPER_ADMIN" && role !== "MODERATOR") {
      return NextResponse.json({ error: "Forbidden access: Admins only" }, { status: 403 });
    }

    const { searchParams } = new URL(request.url);
    const page = Math.max(1, parseInt(searchParams.get("page") || "1", 10));
    const limit = Math.max(1, parseInt(searchParams.get("limit") || "10", 10));
    const search = searchParams.get("search") || "";
    const filter = searchParams.get("filter") || "ALL";

    // Build query filters
    const where: any = {};

    if (filter === "PENDING") {
      where.status = "PENDING_VERIFICATION";
    } else if (filter === "PAID") {
      where.paymentStatus = "SUCCESS";
    } else if (filter === "UNASSIGNED") {
      where.judgeAssignments = {
        none: {},
      };
    }

    if (search.trim()) {
      const searchPattern = search.trim();
      where.OR = [
        {
          registrationId: {
            contains: searchPattern,
            mode: "insensitive",
          },
        },
        {
          student: {
            name: {
              contains: searchPattern,
              mode: "insensitive",
            },
          },
        },
        {
          student: {
            parent: {
              phone: {
                contains: searchPattern,
                mode: "insensitive",
              },
            },
          },
        },
        {
          competitionCategory: {
            category: {
              name: {
                contains: searchPattern,
                mode: "insensitive",
              },
            },
          },
        },
        {
          judgeAssignments: {
            some: {
              judge: {
                name: {
                  contains: searchPattern,
                  mode: "insensitive",
                },
              },
            },
          },
        },
      ];
    }

    // Run query counting and paging in a transaction
    const [
      totalCount,
      registrations,
      totalCountAll,
      pendingCount,
      paidCount,
      unassignedCount
    ] = await prisma.$transaction([
      prisma.registration.count({ where }),
      prisma.registration.findMany({
        where,
        include: {
          student: {
            include: {
              parent: true,
            },
          },
          competitionCategory: {
            include: {
              competition: true,
              category: true,
            },
          },
          judgeAssignments: {
            include: {
              judge: true,
              score: true,
            },
          },
        },
        orderBy: { createdAt: "desc" },
        skip: (page - 1) * limit,
        take: limit,
      }),
      prisma.registration.count(),
      prisma.registration.count({ where: { status: "PENDING_VERIFICATION" } }),
      prisma.registration.count({ where: { paymentStatus: "SUCCESS" } }),
      prisma.registration.count({ where: { judgeAssignments: { none: {} } } }),
    ]);

    const formatted = registrations.map((reg) => ({
      id: reg.id,
      registrationId: reg.registrationId,
      studentName: reg.student.name,
      competitionTitle: reg.competitionCategory.competition.title,
      categoryName: reg.competitionCategory.category.name,
      fbPostUrl: reg.fbPostUrl,
      paymentStatus: reg.paymentStatus,
      status: reg.status,
      scoringFinalized: reg.scoringFinalized,
      createdAt: reg.createdAt,
      assignments: reg.judgeAssignments.map((a) => ({
        id: a.id,
        judgeName: a.judge.name,
        isSubmitted: a.isSubmitted,
        score: a.score ? a.score.totalScore : null,
      })),
    }));

    const totalPages = Math.ceil(totalCount / limit);

    return NextResponse.json({
      registrations: formatted,
      pagination: {
        totalCount,
        totalPages,
        currentPage: page,
        limit,
      },
      metrics: {
        total: totalCountAll,
        pending: pendingCount,
        paid: paidCount,
        unassigned: unassignedCount,
      },
    });
  } catch (error: any) {
    console.error("Admin registrations fetch error:", error);
    return NextResponse.json({ error: "Internal server error occurred" }, { status: 500 });
  }
}

export async function PATCH(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session || !session.user) {
      return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    const role = (session.user as any).role;
    if (role !== "SUPER_ADMIN" && role !== "MODERATOR") {
      return NextResponse.json({ error: "Forbidden access: Admins only" }, { status: 403 });
    }

    const body = await request.json();
    const { id, status, scoringFinalized } = body;

    if (!id) {
      return NextResponse.json({ error: "Registration ID is required" }, { status: 400 });
    }

    const updateData: any = {};
    if (status !== undefined) {
      updateData.status = status;
    }
    if (scoringFinalized !== undefined) {
      updateData.scoringFinalized = scoringFinalized;
    }

    const updated = await prisma.registration.update({
      where: { id },
      data: updateData,
    });

    // Send notifications based on status change (fire-and-forget)
    if (status === "VERIFIED" || status === "REJECTED") {
      const registration = await prisma.registration.findUnique({
        where: { id },
        include: {
          student: true,
          competitionCategory: {
            include: { category: true },
          },
        },
      });

      if (registration) {
        const student = registration.student;
        const parent = await prisma.parent.findFirst({
          where: { id: student.parentId },
        });

        if (parent) {
          const user = await prisma.user.findUnique({
            where: { id: parent.userId },
          });

          if (user?.email) {
            const notificationType = status === "VERIFIED" ? "REGISTRATION_VERIFIED" : "REGISTRATION_REJECTED";
            const title = status === "VERIFIED" ? "Registration Verified" : "Registration Rejected";
            const body = status === "VERIFIED"
              ? `${student.name}'s registration for ${registration.competitionCategory.category.name} has been verified and approved.`
              : `${student.name}'s registration for ${registration.competitionCategory.category.name} has been rejected. Please contact support for more details.`;

            createAndDispatchNotification({
              userId: parent.userId,
              type: notificationType as any,
              title,
              body,
              actionUrl: "/parent/dashboard",
              registrationId: registration.id,
              recipientEmail: user.email,
            }).catch((err) =>
              console.error(`Failed to send ${notificationType} notification:`, err)
            );
          }
        }
      }
    }

    return NextResponse.json({ message: "Registration updated successfully", registration: updated });
  } catch (error: any) {
    console.error("Admin registration update error:", error);
    return NextResponse.json({ error: "Internal server error occurred" }, { status: 500 });
  }
}

