import { NextResponse } from "next/server";
import prisma from "@/lib/db";

export async function GET(req: Request) {
  try {
    const { searchParams } = new URL(req.url);
    const id = searchParams.get("id");
    const scope = searchParams.get("scope"); // STATE | NATIONAL | null (all)
    const stateFilter = searchParams.get("state"); // filter state competitions by eligible state

    // Single competition fetch
    if (id) {
      const competition = await prisma.competition.findUnique({
        where: { id },
        include: {
          categories: { include: { category: true } },
          prizePool: {
            include: {
              items: { orderBy: { createdAt: "asc" } },
            },
          },
        },
      });

      if (!competition) {
        return NextResponse.json({ error: "Competition not found" }, { status: 404 });
      }

      const formattedCategories = competition.categories.map((cc) => ({
        id: cc.id,
        categoryName: `${cc.category.name} (Ages ${cc.minAge}-${cc.maxAge})`,
        minAge: cc.minAge,
        maxAge: cc.maxAge,
      }));

      return NextResponse.json({
        id: competition.id,
        title: competition.title,
        description: competition.description,
        bannerUrl: competition.bannerUrl,
        entryFeeINR: Number(competition.entryFeeINR),
        startDate: competition.startDate,
        endDate: competition.endDate,
        registrationDeadline: competition.registrationDeadline,
        resultDate: competition.resultDate,
        isActive: competition.isActive,
        // Plan 01 — scope fields
        scope: competition.scope,
        eligibleStates: competition.eligibleStates,
        hostState: competition.hostState,
        difficultyLevel: competition.difficultyLevel,
        minJudgesRequired: competition.minJudgesRequired,
        categories: formattedCategories,
        // Plan 02 — prize pool (public preview if published)
        prizePool: competition.prizePool?.isPublished
          ? {
              title: competition.prizePool.title,
              description: competition.prizePool.description,
              items: competition.prizePool.items.map((item) => ({
                rank: item.rank,
                type: item.type,
                title: item.title,
                description: item.description,
                estimatedValue: item.estimatedValue ? Number(item.estimatedValue) : null,
                isPhysical: item.isPhysical,
                imageUrl: item.imageUrl,
              })),
            }
          : null,
      });
    }

    // List competitions with optional scope/state filtering
    const competitions = await prisma.competition.findMany({
      where: {
        isActive: true,
        ...(scope ? { scope: scope as any } : {}),
        ...(stateFilter
          ? {
              OR: [
                { scope: "NATIONAL" }, // Nationals are always visible
                { eligibleStates: { has: stateFilter } },
              ],
            }
          : {}),
      },
      include: {
        categories: { 
          include: { 
            category: true,
            _count: {
              select: { registrations: true }
            }
          } 
        },
        prizePool: { 
          include: { items: true }
        },
      },
      orderBy: { registrationDeadline: "asc" },
    });

    return NextResponse.json(
      competitions.map((comp) => {
        const minAges = comp.categories.map((c) => c.minAge);
        const maxAges = comp.categories.map((c) => c.maxAge);
        const minAge = minAges.length > 0 ? Math.min(...minAges) : 4;
        const maxAge = maxAges.length > 0 ? Math.max(...maxAges) : 16;

        let prizeSummary = null;
        if (comp.prizePool?.isPublished && comp.prizePool.items.length > 0) {
          const prizeTypes = Array.from(new Set(comp.prizePool.items.map(item => {
            if (item.type === "CASH_PRIZE" && item.estimatedValue) {
              return `₹${Number(item.estimatedValue)} Cash`;
            }
            if (item.type === "PHYSICAL_TROPHY") return "Trophy";
            if (item.type === "PHYSICAL_MEDAL") return "Medal";
            return null;
          }).filter(Boolean)));
          if (prizeTypes.length > 0) {
            prizeSummary = prizeTypes.join(" + ");
          }
        }

        const joinees = comp.categories.reduce((sum, c) => sum + c._count.registrations, 0);
        const capacity = comp.scope === "NATIONAL" ? 1000 : 300;
        const slotsLeft = Math.max(0, capacity - joinees);

        return {
          id: comp.id,
          title: comp.title,
          description: comp.description,
          bannerUrl: comp.bannerUrl,
          entryFeeINR: Number(comp.entryFeeINR),
          startDate: comp.startDate,
          endDate: comp.endDate,
          registrationDeadline: comp.registrationDeadline,
          resultDate: comp.resultDate,
          isActive: comp.isActive,
          scope: comp.scope,
          hostState: comp.hostState,
          eligibleStates: comp.eligibleStates,
          difficultyLevel: comp.difficultyLevel,
          hasPrizePool: comp.prizePool?.isPublished ?? false,
          categoryName: Array.from(new Set(comp.categories.map((c) => c.category.name))).join(", ") || "General Arts",
          minAge,
          maxAge,
          prizeSummary,
          joinees,
          slotsLeft,
          capacity
        };
      })
    );
  } catch (error: any) {
    console.error("Fetch competition error:", error);
    return NextResponse.json({ error: "Internal server error" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/db";
import { createAndDispatchNotification } from "@/lib/notificationService";

export async function POST(request: NextRequest) {
  try {
    // Verify cron secret
    const cronSecret = request.headers.get("Authorization");
    if (cronSecret !== `Bearer ${process.env.CRON_SECRET}`) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Find judge assignments that haven't been submitted for 3+ days
    const threeDaysAgo = new Date(Date.now() - 3 * 24 * 60 * 60 * 1000);

    const overdueAssignments = await prisma.judgeAssignment.findMany({
      where: {
        isSubmitted: false,
        assignedAt: {
          lte: threeDaysAgo,
        },
      },
      include: {
        judge: {
          include: { user: true },
        },
        registration: {
          include: {
            student: true,
            competitionCategory: {
              include: { category: true },
            },
          },
        },
      },
    });

    if (overdueAssignments.length === 0) {
      return NextResponse.json({
        message: "No overdue assignments to remind",
        count: 0,
      });
    }

    let remindersSent = 0;

    for (const assignment of overdueAssignments) {
      const judge = assignment.judge;
      const registration = assignment.registration;
      const student = registration.student;
      const daysAgo = Math.floor((Date.now() - assignment.assignedAt.getTime()) / (24 * 60 * 60 * 1000));

      createAndDispatchNotification({
        userId: assignment.judgeId,
        type: "SCORING_REMINDER",
        title: "Scoring Reminder",
        body: `Please submit your scores for ${student.name}'s ${registration.competitionCategory.category.name} submission. This was assigned ${daysAgo} days ago.`,
        actionUrl: "/judge/dashboard",
        assignmentId: assignment.id,
        registrationId: registration.id,
        recipientEmail: judge.user.email,
        recipientPhone: judge.telegramChatId || undefined,
      }).catch((err) => console.error("Failed to send scoring reminder:", err));

      remindersSent++;
    }

    return NextResponse.json({
      message: `Sent ${remindersSent} scoring reminders`,
      count: remindersSent,
    });
  } catch (error: any) {
    console.error("Scoring reminders cron error:", error);
    return NextResponse.json({ error: "Internal server error occurred" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/db";
import { sendTelegramWithTracking } from "@/lib/notifications";
import { DeliveryStatus } from "@prisma/client";

/**
 * POST /api/cron/telegram-retry
 * Retry temporarily failed Telegram messages
 * Requires CRON_SECRET bearer token in Authorization header
 */
export async function POST(request: NextRequest) {
  const authHeader = request.headers.get("authorization");
  const cronSecret = process.env.CRON_SECRET;

  if (!cronSecret || authHeader !== `Bearer ${cronSecret}`) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  try {
    // Find all temporarily failed deliveries that are due for retry
    const failedDeliveries = await prisma.telegramMessageDelivery.findMany({
      where: {
        status: DeliveryStatus.TEMPORARILY_FAILED,
        nextRetryAt: { lte: new Date() },
        failureCount: { lt: 10 }, // Max 10 attempts per delivery
      },
      include: { notification: true },
      take: 100, // Process max 100 per cron run to avoid timeout
      orderBy: { nextRetryAt: "asc" },
    });

    const results = {
      processed: 0,
      succeeded: 0,
      failed: 0,
      details: [] as any[],
    };

    console.log(
      `[Telegram Retry Cron] Starting retry for ${failedDeliveries.length} temporarily failed deliveries`
    );

    for (const delivery of failedDeliveries) {
      results.processed++;

      try {
        const notification = delivery.notification;
        const message = `<b>${notification.title}</b>\n\n${notification.body}`;

        await sendTelegramWithTracking(
          notification.id,
          delivery.chatId,
          message
        );

        results.succeeded++;
        results.details.push({
          deliveryId: delivery.id,
          chatId: delivery.chatId,
          status: "retried_succeeded",
          previousFailures: delivery.failureCount,
        });
      } catch (error) {
        results.failed++;
        results.details.push({
          deliveryId: delivery.id,
          chatId: delivery.chatId,
          status: "retried_failed",
          error: error instanceof Error ? error.message : "Unknown error",
          previousFailures: delivery.failureCount,
        });
      }
    }

    console.log(
      `[Telegram Retry Cron] Completed: ${results.succeeded} succeeded, ${results.failed} failed out of ${results.processed}`
    );

    return NextResponse.json({
      success: true,
      results,
      timestamp: new Date().toISOString(),
    });
  } catch (error) {
    console.error("[Telegram Retry Cron] Error:", error);
    return NextResponse.json(
      {
        error: "Cron job failed",
        details: error instanceof Error ? error.message : "Unknown error",
      },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/db";
import { getJudgeRate } from "@/lib/constants";

export async function GET() {
  try {
    const session = await getServerSession(authOptions);
    if (!session || !session.user) {
      return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    const userId = (session.user as any).id;

    // Get judge profile
    const judge = await prisma.judge.findUnique({
      where: { userId },
      include: {
        assignments: {
          include: {
            registration: {
              include: {
                competitionCategory: {
                  include: {
                    competition: true,
                    category: true,
                  },
                },
              },
            },
            score: true,
          },
        },
        payouts: true,
      },
    });

    if (!judge) {
      return NextResponse.json({ error: "Judge profile not found" }, { status: 404 });
    }

    const assignments = judge.assignments;
    const completedAssignments = assignments.filter((asg) => asg.isSubmitted);
    const pendingAssignmentsCount = assignments.length - completedAssignments.length;

    // Calculate dynamic earnings based on Plan 07 rate matrix
    let totalUnpaidEarnings = 0;
    let totalEarnings = 0;

    // Dynamic sum of completed evaluations mapped to their specific competition scope rates
    completedAssignments.forEach((asg) => {
      const scope = asg.registration.competitionCategory.competition.scope as "STATE" | "NATIONAL";
      const rate = getJudgeRate(judge.tier, scope);
      totalEarnings += rate;
    });

    // Substract paid payouts to get pending balance
    const totalPaidPayouts = judge.payouts
      .filter((p) => p.status === "PAID")
      .reduce((sum, p) => sum + Number(p.amount), 0);

    totalUnpaidEarnings = Math.max(0, totalEarnings - totalPaidPayouts);

    // Calculate average score given vs category global average
    const judgeAverageScore = judge.averageScoreGiven ? Number(judge.averageScoreGiven) : null;
    
    // Get list of category IDs this judge evaluated
    const categoryIdsEvaluated = Array.from(
      new Set(
        completedAssignments.map((asg) => asg.registration.competitionCategory.categoryId)
      )
    );

    let peerAverageScore = null;
    if (categoryIdsEvaluated.length > 0) {
      const peerScores = await prisma.score.aggregate({
        where: {
          assignment: {
            registration: {
              competitionCategory: {
                categoryId: { in: categoryIdsEvaluated },
              },
            },
          },
        },
        _avg: {
          totalScore: true,
        },
      });
      peerAverageScore = peerScores._avg.totalScore ? Number(peerScores._avg.totalScore.toFixed(2)) : null;
    }

    // Workload category distribution counts
    const categoryCounts: Record<string, number> = {};
    assignments.forEach((asg) => {
      const name = asg.registration.competitionCategory.category.name;
      categoryCounts[name] = (categoryCounts[name] || 0) + 1;
    });

    const categoryDistribution = Object.entries(categoryCounts).map(([name, count]) => ({
      name,
      count,
    }));

    return NextResponse.json({
      metrics: {
        pendingCount: pendingAssignmentsCount,
        completedCount: completedAssignments.length,
        lifetimeCount: judge.totalEvaluations,
        totalEarnings,
        totalPaidPayouts,
        pendingPayoutBalance: totalUnpaidEarnings,
        judgeAverageScore,
        peerAverageScore,
      },
      categoryDistribution,
    });
  } catch (error: any) {
    console.error("Judge analytics API failure:", error);
    return NextResponse.json({ error: "Internal server error occurred" }, { status: 500 });
  }
}

import { NextResponse, NextRequest } from "next/server";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/db";

export async function GET(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session || !session.user) {
      return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    const userId = (session.user as any).id;

    // Get judge profile linked to user ID
    const judge = await prisma.judge.findUnique({
      where: { userId },
    });

    if (!judge) {
      return NextResponse.json({ error: "Judge profile not found" }, { status: 404 });
    }

    // Parse pagination parameters from query string
    const { searchParams } = new URL(request.url);
    const page = parseInt(searchParams.get("page") || "1", 10);
    const limit = parseInt(searchParams.get("limit") || "10", 10);

    // Validate pagination parameters
    const validPage = Math.max(1, page);
    const validLimit = Math.max(1, Math.min(limit, 100)); // Cap at 100 per page
    const skip = (validPage - 1) * validLimit;

    // Get total count of assignments
    const totalCount = await prisma.judgeAssignment.count({
      where: { judgeId: judge.id },
    });

    // Get paginated assignments
    const assignments = await prisma.judgeAssignment.findMany({
      where: { judgeId: judge.id },
      include: {
        registration: {
          include: {
            competitionCategory: {
              include: {
                competition: true,
                category: true,
              },
            },
          },
        },
        score: true,
      },
      orderBy: { assignedAt: "desc" },
      skip,
      take: validLimit,
    });

    const formatted = assignments.map((asg) => ({
      id: asg.id,
      registrationId: asg.registration.registrationId, // Blinded Roll ID only
      competitionTitle: asg.registration.competitionCategory.competition.title,
      categoryName: asg.registration.competitionCategory.category.name,
      fbPostUrl: asg.registration.fbPostUrl,
      isSubmitted: asg.isSubmitted,
      assignedAt: asg.assignedAt,
      submittedAt: asg.submittedAt,
      scope: asg.registration.competitionCategory.competition.scope,
      score: asg.score
        ? {
            criteria1: asg.score.criteria1,
            criteria2: asg.score.criteria2,
            criteria3: asg.score.criteria3,
            criteria4: asg.score.criteria4 || undefined,
            totalScore: asg.score.totalScore,
            remarks: asg.score.remarks,
          }
        : null,
    }));

    const totalPages = Math.ceil(totalCount / validLimit);

    return NextResponse.json({
      assignments: formatted,
      pagination: {
        currentPage: validPage,
        totalPages,
        totalCount,
        limit: validLimit,
        hasNextPage: validPage < totalPages,
        hasPreviousPage: validPage > 1,
      },
    });
  } catch (error: any) {
    console.error("Judge assignments fetch error:", error);
    return NextResponse.json({ error: "Internal server error occurred" }, { status: 500 });
  }
}

