export async function PATCH(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session || !session.user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const userId = (session.user as any).id;
    const body = await request.json();
    const { type, channel, enabled } = body;

    if (!type || !channel) {
      return NextResponse.json(
        { error: "type and channel are required" },
        { status: 400 }
      );
    }

    // Validate channel is one of the allowed values
    if (!Object.values(NotificationChannel).includes(channel)) {
      return NextResponse.json(
        { error: `Invalid channel: ${channel}` },
        { status: 400 }
      );
    }

    // Validate type is one of the allowed values
    if (!Object.values(NotificationType).includes(type)) {
      return NextResponse.json(
        { error: `Invalid notification type: ${type}` },
        { status: 400 }
      );
    }

    const preference = await prisma.notificationPreference.upsert({
      where: {
        userId_type_channel: {
          userId,
          type,
          channel,
        },
      },
      update: {
        enabled: enabled !== undefined ? enabled : true,
      },
      create: {
        userId,
        type,
        channel,
        enabled: enabled !== undefined ? enabled : true,
      },
    });

    return NextResponse.json({
      message: "Preference updated successfully",
      preference,
    });
  } catch (error: any) {
    console.error("Notification preference update error:", error);
    return NextResponse.json({ error: "Internal server error occurred" }, { status: 500 });
  }
}

import { NextResponse, NextRequest } from "next/server";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/db";

export interface NotificationItem {
  id: string;
  type: string;
  title: string;
  body: string;
  read: boolean;
  actionUrl?: string;
  createdAt: string;
}

export async function GET(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session || !session.user) {
      return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    const userId = (session.user as any).id;
    const searchParams = request.nextUrl.searchParams;
    const page = Math.max(1, parseInt(searchParams.get("page") || "1"));
    const limit = Math.min(50, parseInt(searchParams.get("limit") || "20"));
    const skip = (page - 1) * limit;

    // Fetch paginated notifications from the database
    const [notifications, totalCount, unreadCount] = await Promise.all([
      prisma.notification.findMany({
        where: { userId },
        orderBy: { createdAt: "desc" },
        skip,
        take: limit,
      }),
      prisma.notification.count({ where: { userId } }),
      prisma.notification.count({ where: { userId, read: false } }),
    ]);

    const mappedNotifications: NotificationItem[] = notifications.map((n) => ({
      id: n.id,
      type: n.type,
      title: n.title,
      body: n.body,
      read: n.read,
      actionUrl: n.actionUrl || undefined,
      createdAt: n.createdAt.toISOString(),
    }));

    const totalPages = Math.ceil(totalCount / limit);

    return NextResponse.json({
      notifications: mappedNotifications,
      unreadCount,
      totalCount,
      page,
      totalPages,
      limit,
    });
  } catch (error: any) {
    console.error("Notifications fetch error:", error);
    return NextResponse.json(
      { error: "Internal server error occurred" },
      { status: 500 }
    );
  }
}

export async function PATCH(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session || !session.user) {
      return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    const userId = (session.user as any).id;
    const body = await request.json();
    const { id, markAll } = body;

    let updated = 0;

    if (markAll) {
      // Mark all unread notifications as read
      const result = await prisma.notification.updateMany({
        where: { userId, read: false },
        data: { read: true, readAt: new Date() },
      });
      updated = result.count;
    } else if (id) {
      // Mark single notification as read
      const notification = await prisma.notification.findFirst({
        where: { id, userId },
      });

      if (!notification) {
        return NextResponse.json({ error: "Notification not found" }, { status: 404 });
      }

      await prisma.notification.update({
        where: { id },
        data: { read: true, readAt: new Date() },
      });
      updated = 1;
    } else {
      return NextResponse.json(
        { error: "Either 'id' or 'markAll' must be provided" },
        { status: 400 }
      );
    }

    return NextResponse.json({ success: true, updated });
  } catch (error: any) {
    console.error("Notification update error:", error);
    return NextResponse.json(
      { error: "Internal server error occurred" },
      { status: 500 }
    );
  }
}

export async function DELETE(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);
    if (!session || !session.user) {
      return NextResponse.json({ error: "Unauthorized access" }, { status: 401 });
    }

    const userId = (session.user as any).id;
    const body = await request.json();
    const { id } = body;

    if (!id) {
      return NextResponse.json({ error: "Notification id is required" }, { status: 400 });
    }

    // Verify the notification belongs to the user
    const notification = await prisma.notification.findFirst({
      where: { id, userId },
    });

    if (!notification) {
      return NextResponse.json({ error: "Notification not found" }, { status: 404 });
    }

    await prisma.notification.delete({ where: { id } });

    return NextResponse.json({ success: true, deleted: true });
  } catch (error: any) {
    console.error("Notification delete error:", error);
    return NextResponse.json(
      { error: "Internal server error occurred" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import prisma from "@/lib/db";

// Use serverless runtime for better compatibility with long-lived connections
// Note: Vercel's serverless functions have a 30s timeout by default
export const maxDuration = 30;

export async function GET(req: NextRequest) {
  const session = await getServerSession(authOptions);
  if (!session || !session.user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const userId = (session.user as any).id;
  const lastSeenAtParam = req.nextUrl.searchParams.get("lastSeenAt");
  let lastSeenAt = lastSeenAtParam ? new Date(lastSeenAtParam) : new Date(Date.now() - 5 * 60000); // Default to 5 minutes ago

  const encoder = new TextEncoder();

  // Create a readable stream for SSE
  const stream = new ReadableStream({
    async start(controller) {
      const sendHeartbeat = () => {
        try {
          controller.enqueue(encoder.encode(": heartbeat\n\n"));
        } catch (e) {
          controller.close();
        }
      };

      const sendNotification = async () => {
        try {
          // Poll for new notifications since lastSeenAt
          const newNotifications = await prisma.notification.findMany({
            where: {
              userId,
              createdAt: { gt: lastSeenAt },
            },
            orderBy: { createdAt: "asc" },
            take: 10, // Limit to avoid overwhelming
          });

          if (newNotifications.length > 0) {
            for (const notif of newNotifications) {
              const data = {
                id: notif.id,
                type: notif.type,
                title: notif.title,
                body: notif.body,
                read: notif.read,
                actionUrl: notif.actionUrl,
                createdAt: notif.createdAt,
              };

              controller.enqueue(
                encoder.encode(`event: new_notification\ndata: ${JSON.stringify(data)}\n\n`)
              );

              lastSeenAt = new Date(Math.max(lastSeenAt.getTime(), notif.createdAt.getTime()));
            }
          }
        } catch (e) {
          console.error("SSE notification fetch error:", e);
        }
      };

      let pollInterval: NodeJS.Timeout | null = null;
      let heartbeatInterval: NodeJS.Timeout | null = null;

      try {
        // Initial notification fetch
        await sendNotification();

        // Set up polling (every 15 seconds)
        pollInterval = setInterval(sendNotification, 15000);

        // Set up heartbeat (every 30 seconds)
        heartbeatInterval = setInterval(sendHeartbeat, 30000);

        // Clean up on client disconnect
        req.signal.addEventListener("abort", () => {
          if (pollInterval) clearInterval(pollInterval);
          if (heartbeatInterval) clearInterval(heartbeatInterval);
          controller.close();
        });
      } catch (e) {
        console.error("SSE setup error:", e);
        controller.close();
      }
    },
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
      "X-Accel-Buffering": "no",
    },
  });
}

