      { registrationId: "REG-REC-102", studentName: "Rohan Sen", categoryName: "Kabyo-Geeti (Poetic Songs)", finalScore: 91.2, finalRank: 2, fbPostUrl: "https://facebook.com/groups/pratibhaparishad/posts/2" },
      { registrationId: "REG-REC-103", studentName: "Tiyasa Das", categoryName: "Srijoni Abritti (Creative Recitation)", finalScore: 89.8, finalRank: 3, fbPostUrl: "https://facebook.com/groups/pratibhaparishad/posts/3" }
