      { registrationId: "REG-SNG-202", studentName: "Megha Banerjee", categoryName: "Rabindra Sangeet", finalScore: 93.4, finalRank: 2, fbPostUrl: "https://facebook.com/groups/pratibhaparishad/posts/5" },
      { registrationId: "REG-SNG-203", studentName: "Sneha Ghoshal", categoryName: "Rabindra Sangeet", finalScore: 91.0, finalRank: 3, fbPostUrl: "https://facebook.com/groups/pratibhaparishad/posts/6" }
    ],
    "comp-draw-03": [
      { registrationId: "REG-DRW-301", studentName: "Aritra Paul", categoryName: "Creative Canvas (Drawing)", finalScore: 95.0, finalRank: 1, fbPostUrl: "https://facebook.com/groups/pratibhaparishad/posts/7" },
      { registrationId: "REG-DRW-302", studentName: "Tiyasa Sen", categoryName: "Creative Canvas (Drawing)", finalScore: 92.5, finalRank: 2, fbPostUrl: "https://facebook.com/groups/pratibhaparishad/posts/8" },
      { registrationId: "REG-DRW-303", studentName: "Ishita Kundu", categoryName: "Sundar Aksher (Handwriting)", finalScore: 88.7, finalRank: 3, fbPostUrl: "https://facebook.com/groups/pratibhaparishad/posts/9" }
