              {comp.slotsLeft <= 20 ? `⚡ Only ${comp.slotsLeft} slots left!` : `${comp.slotsLeft} slots remaining`}
            </span>
          </div>
          {/* Progress Bar */}
          <div className="w-full h-1.5 bg-charcoal/10 dark:bg-cream/10 rounded-full overflow-hidden">
            <div 
              className={`h-full rounded-full transition-all duration-500 ${
                comp.slotsLeft <= 20 ? "bg-terracotta animate-pulse" : "bg-gold"
              }`}
              style={{ width: `${Math.min(100, (comp.joinees / comp.capacity) * 100)}%` }}
            />
          </div>
        </div>

        {/* Title */}
        <h2 className="font-serif text-xl font-bold text-charcoal dark:text-cream leading-snug">
          {comp.title}
        </h2>

        <p className="font-sans text-sm text-charcoal/70 dark:text-cream/70 leading-relaxed line-clamp-3">
          {comp.description}
        </p>

        {/* Timeline */}
        <div className="pt-4 border-t border-terracotta/5 dark:border-terracotta/10 space-y-2.5 font-sans text-xs text-charcoal/60 dark:text-cream/60">
          <div className="flex flex-wrap gap-1 justify-between">
            <span className="flex items-center gap-1.5"><Calendar className="w-3.5 h-3.5 text-gold-dark dark:text-gold" />Registration Closes:</span>
            <span className="font-bold text-charcoal dark:text-cream">{formatDate(comp.registrationDeadline)}</span>
          </div>
          <div className="flex flex-wrap gap-1 justify-between">
            <span className="flex items-center gap-1.5"><Calendar className="w-3.5 h-3.5 text-gold-dark dark:text-gold" />Evaluation Closes:</span>
            <span className="font-bold text-charcoal dark:text-cream">{formatDate(comp.endDate)}</span>
          </div>
          <div className="flex flex-wrap gap-1 justify-between">
            <span className="flex items-center gap-1.5"><Calendar className="w-3.5 h-3.5 text-gold-dark dark:text-gold" />Results Published:</span>
            <span className="font-bold text-terracotta dark:text-gold">{formatDate(comp.resultDate)}</span>
          </div>
        </div>
      </div>

      {/* Action */}
      <div className="pt-6 mt-6 border-t border-terracotta/5 dark:border-terracotta/10">
        {isDeadlinePassed ? (
          <Button
            disabled
            variant="secondary"
            size="lg"
            className="w-full"
            aria-disabled="true"
          >
            Registration Closed
          </Button>
        ) : (
          <Link
            href={`/competitions/${slugify(comp.title)}-${comp.id}`}
            id={`view-comp-${comp.id}`}
            className={`w-full inline-flex items-center justify-center gap-2 py-3.5 rounded-xl font-sans text-sm font-bold shadow-md hover:shadow-lg transition-all duration-300 ${
              isNational
                ? "bg-gold hover:bg-gold-light text-charcoal"
                : "bg-terracotta hover:bg-terracotta-light text-cream"
            }`}
          >
            View Details & Register
            <ArrowRight className="w-4 h-4" aria-hidden="true" />
          </Link>
        )}
      </div>
    </article>
  );
}

function slugify(text: string): string {
  return text
    .toString()
    .toLowerCase()
    .trim()
    .replace(/\s+/g, "-")
    .replace(/[^\w\-]+/g, "")
    .replace(/\-\-+/g, "-")
    .replace(/^-+/, "")
    .replace(/-+$/, "");
}

"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useState, useEffect, useCallback } from "react";
import { X } from "lucide-react";
import Header from "@/components/Header";
import Button from "@/components/Button";

export default function JudgeProfilePage() {
  const { status } = useSession();
  const router = useRouter();
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [successMessage, setSuccessMessage] = useState("");
  const [errorMessage, setErrorMessage] = useState("");

  const [formData, setFormData] = useState({
    email: "",
    name: "",
    specializations: [] as string[],
    assignmentCount: 0,
    profileImageUrl: "",
  });

  const [tagInput, setTagInput] = useState("");

  const fetchProfile = useCallback(async () => {
    try {
      const response = await fetch("/api/judge/profile");
      if (response.ok) {
        const data = await response.json();
        setFormData(data);
      } else {
        setErrorMessage("Failed to load profile data");
      }
    } catch (error) {
      console.error("Profile fetch error:", error);
      setErrorMessage("Failed to load profile data");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/login");
      return;
    }

    if (status === "authenticated") {
      Promise.resolve().then(() => {
        fetchProfile();
      });
    }
  }, [status, router, fetchProfile]);

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData((prev) => ({
      ...prev,
      name: e.target.value,
    }));
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        setFormData((prev) => ({
          ...prev,
          profileImageUrl: base64,
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleTagInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setTagInput(e.target.value);
  };

  const handleTagInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Enter" || e.key === ",") {
      e.preventDefault();
      addTag();
    }
  };

  const addTag = () => {
    const trimmed = tagInput.trim();
    if (trimmed && !formData.specializations.includes(trimmed)) {
      setFormData((prev) => ({
        ...prev,
        specializations: [...prev.specializations, trimmed],
      }));
      setTagInput("");
    }
  };

  const removeTag = (index: number) => {
    setFormData((prev) => ({
      ...prev,
      specializations: prev.specializations.filter((_, i) => i !== index),
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    setSuccessMessage("");
    setErrorMessage("");

    try {
      const response = await fetch("/api/judge/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: formData.name,
          specializations: formData.specializations,
          profileImage: formData.profileImageUrl.startsWith("data:") ? formData.profileImageUrl : null,
        }),
      });

      if (response.ok) {
        setSuccessMessage("Profile updated successfully");
        setTimeout(() => setSuccessMessage(""), 3000);
      } else {
        const data = await response.json();
        setErrorMessage(data.error || "Failed to update profile");
      }
    } catch (error) {
      console.error("Profile update error:", error);
      setErrorMessage("Failed to update profile");
    } finally {
      setSubmitting(false);
    }
  };

  if (status === "loading" || loading) {
    return (
      <div className="min-h-screen bg-cream dark:bg-charcoal flex items-center justify-center">
        <div className="text-charcoal dark:text-cream">Loading...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-cream dark:bg-charcoal flex flex-col">
      <Header isAdmin={false} />
      <main className="flex-1 flex items-center justify-center px-4 py-12">
        <div className="w-full max-w-2xl bg-cream border border-terracotta/10 rounded-2xl p-6 sm:p-8 shadow-md dark:bg-charcoal dark:border-terracotta/20">
          <h1 className="text-3xl font-serif font-bold text-charcoal dark:text-cream mb-8">
            My Profile
          </h1>

          {/* Profile Image Section */}
          <div className="mb-8 flex flex-col items-center gap-4">
            <div className="w-24 h-24 rounded-full bg-terracotta/10 dark:bg-gold/10 border-2 border-terracotta/20 dark:border-gold/20 flex items-center justify-center overflow-hidden">
              {formData.profileImageUrl && formData.profileImageUrl.startsWith("data:") ? (
                <img src={formData.profileImageUrl} alt="Profile" className="w-full h-full object-cover" />
              ) : formData.profileImageUrl ? (
                <img src={formData.profileImageUrl} alt="Profile" className="w-full h-full object-cover" />
              ) : (
                <svg className="w-12 h-12 text-terracotta/40 dark:text-gold/40" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm0 3c1.66 0 3 1.34 3 3s-1.34 3-3 3-3-1.34-3-3 1.34-3 3-3zm0 14.2c-2.5 0-4.71-1.28-6-3.22.03-1.99 4-3.08 6-3.08 1.99 0 5.97 1.09 6 3.08-1.29 1.94-3.5 3.22-6 3.22z" />
                </svg>
              )}
            </div>
            <label className="px-4 py-2 rounded-lg bg-terracotta/10 dark:bg-gold/10 text-terracotta dark:text-gold font-semibold text-sm cursor-pointer hover:bg-terracotta/20 dark:hover:bg-gold/20 transition-colors">
              Change Photo
              <input
                type="file"
                accept="image/*"
                onChange={handleImageChange}
                className="hidden"
              />
            </label>
          </div>

          {successMessage && (
            <div className="mb-6 p-4 rounded-xl bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-100">
