"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useState, useEffect, useCallback } from "react";
import Header from "@/components/Header";
import Footer from "@/components/Footer";
import Button from "@/components/Button";

export default function ParentProfilePage() {
  const { status } = useSession();
  const router = useRouter();
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [successMessage, setSuccessMessage] = useState("");
  const [errorMessage, setErrorMessage] = useState("");

  const [formData, setFormData] = useState({
    email: "",
    name: "",
    phone: "",
    address: "",
    city: "",
    state: "",
    postalCode: "",
    country: "",
    profileImageUrl: "",
  });

  const fetchProfile = useCallback(async () => {
    try {
      const response = await fetch("/api/parent/profile");
      if (response.ok) {
        const data = await response.json();
        setFormData(data);
      } else {
        setErrorMessage("Failed to load profile data");
      }
    } catch (error) {
      console.error("Profile fetch error:", error);
      setErrorMessage("Failed to load profile data");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/login");
      return;
    }

    if (status === "authenticated") {
      Promise.resolve().then(() => {
        fetchProfile();
      });
    }
  }, [status, router, fetchProfile]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const base64 = event.target?.result as string;
        setFormData((prev) => ({
          ...prev,
          profileImageUrl: base64,
        }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    setSuccessMessage("");
    setErrorMessage("");

    try {
      const response = await fetch("/api/parent/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: formData.name,
          phone: formData.phone,
          address: formData.address,
          city: formData.city,
          state: formData.state,
          postalCode: formData.postalCode,
          country: formData.country,
          profileImage: formData.profileImageUrl.startsWith("data:") ? formData.profileImageUrl : null,
        }),
      });

      if (response.ok) {
        setSuccessMessage("Profile updated successfully");
        setTimeout(() => setSuccessMessage(""), 3000);
      } else {
        const data = await response.json();
        setErrorMessage(data.error || "Failed to update profile");
      }
    } catch (error) {
      console.error("Profile update error:", error);
      setErrorMessage("Failed to update profile");
    } finally {
      setSubmitting(false);
    }
  };

  if (status === "loading" || loading) {
    return (
      <div className="min-h-screen bg-cream dark:bg-charcoal flex flex-col">
        <Header />
        <div className="flex-1 flex items-center justify-center">
          <div className="w-10 h-10 border-4 border-terracotta dark:border-gold border-t-transparent rounded-full animate-spin" />
        </div>
        <Footer />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-cream dark:bg-charcoal flex flex-col">
      <Header />
      <main className="flex-1 flex items-center justify-center px-4 py-12">
        <div className="w-full max-w-2xl bg-cream border border-terracotta/10 rounded-2xl p-6 sm:p-8 shadow-md dark:bg-charcoal dark:border-terracotta/20">
          <h1 className="text-3xl font-serif font-bold text-charcoal dark:text-cream mb-8">
            My Profile
          </h1>

          {/* Profile Image Section */}
          <div className="mb-8 flex flex-col items-center gap-4">
            <div className="w-24 h-24 rounded-full bg-terracotta/10 dark:bg-gold/10 border-2 border-terracotta/20 dark:border-gold/20 flex items-center justify-center overflow-hidden">
              {formData.profileImageUrl && formData.profileImageUrl.startsWith("data:") ? (
                <img src={formData.profileImageUrl} alt="Profile" className="w-full h-full object-cover" />
              ) : formData.profileImageUrl ? (
                <img src={formData.profileImageUrl} alt="Profile" className="w-full h-full object-cover" />
              ) : (
                <svg className="w-12 h-12 text-terracotta/40 dark:text-gold/40" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm0 3c1.66 0 3 1.34 3 3s-1.34 3-3 3-3-1.34-3-3 1.34-3 3-3zm0 14.2c-2.5 0-4.71-1.28-6-3.22.03-1.99 4-3.08 6-3.08 1.99 0 5.97 1.09 6 3.08-1.29 1.94-3.5 3.22-6 3.22z" />
                </svg>
              )}
            </div>
            <label className="px-4 py-3 rounded-lg bg-terracotta/10 dark:bg-gold/10 text-terracotta dark:text-gold font-semibold text-sm cursor-pointer hover:bg-terracotta/20 dark:hover:bg-gold/20 transition-colors">
              Change Photo
              <input
                type="file"
                accept="image/*"
                onChange={handleImageChange}
                className="hidden"
              />
            </label>
          </div>

          {successMessage && (
            <div className="mb-6 p-4 rounded-xl bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-100">
              {successMessage}
            </div>
          )}

          {errorMessage && (
            <div className="mb-6 p-4 rounded-xl bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-100">
              {errorMessage}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-sm font-semibold text-charcoal/70 dark:text-cream/70 mb-2">
                Email (Read-only)
              </label>
              <input
                type="email"
                value={formData.email}
                disabled
                className="w-full px-4 py-3 rounded-xl border border-terracotta/10 bg-terracotta/5 dark:bg-gold/5 text-charcoal dark:text-cream/70 cursor-not-allowed"
              />
            </div>

            <div>
              <label className="block text-sm font-semibold text-charcoal dark:text-cream mb-2">
                Full Name
              </label>
              <input
                type="text"
                name="name"
                value={formData.name}
                onChange={handleChange}
                className="w-full px-4 py-3 rounded-xl border border-terracotta/20 dark:border-terracotta/40 bg-white dark:bg-charcoal/50 text-charcoal dark:text-cream placeholder:text-charcoal/40 dark:placeholder:text-cream/40 focus:outline-none focus:border-terracotta dark:focus:border-gold transition-colors"
              />
            </div>

            <div>
              <label className="block text-sm font-semibold text-charcoal dark:text-cream mb-2">
                Phone Number
              </label>
              <input
                type="tel"
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                className="w-full px-4 py-3 rounded-xl border border-terracotta/20 dark:border-terracotta/40 bg-white dark:bg-charcoal/50 text-charcoal dark:text-cream placeholder:text-charcoal/40 dark:placeholder:text-cream/40 focus:outline-none focus:border-terracotta dark:focus:border-gold transition-colors"
              />
            </div>

            <div>
              <label className="block text-sm font-semibold text-charcoal dark:text-cream mb-2">
                Address
              </label>
              <input
                type="text"
                name="address"
                value={formData.address}
                onChange={handleChange}
                className="w-full px-4 py-3 rounded-xl border border-terracotta/20 dark:border-terracotta/40 bg-white dark:bg-charcoal/50 text-charcoal dark:text-cream placeholder:text-charcoal/40 dark:placeholder:text-cream/40 focus:outline-none focus:border-terracotta dark:focus:border-gold transition-colors"
              />
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-semibold text-charcoal dark:text-cream mb-2">
                  City
                </label>
                <input
                  type="text"
                  name="city"
                  value={formData.city}
                  onChange={handleChange}
                  className="w-full px-4 py-3 rounded-xl border border-terracotta/20 dark:border-terracotta/40 bg-white dark:bg-charcoal/50 text-charcoal dark:text-cream placeholder:text-charcoal/40 dark:placeholder:text-cream/40 focus:outline-none focus:border-terracotta dark:focus:border-gold transition-colors"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-charcoal dark:text-cream mb-2">
                  State
                </label>
                <input
                  type="text"
                  name="state"
                  value={formData.state}
                  onChange={handleChange}
                  className="w-full px-4 py-3 rounded-xl border border-terracotta/20 dark:border-terracotta/40 bg-white dark:bg-charcoal/50 text-charcoal dark:text-cream placeholder:text-charcoal/40 dark:placeholder:text-cream/40 focus:outline-none focus:border-terracotta dark:focus:border-gold transition-colors"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-semibold text-charcoal dark:text-cream mb-2">
                  Postal Code
                </label>
                <input
                  type="text"
                  name="postalCode"
                  value={formData.postalCode}
                  onChange={handleChange}
                  className="w-full px-4 py-3 rounded-xl border border-terracotta/20 dark:border-terracotta/40 bg-white dark:bg-charcoal/50 text-charcoal dark:text-cream placeholder:text-charcoal/40 dark:placeholder:text-cream/40 focus:outline-none focus:border-terracotta dark:focus:border-gold transition-colors"
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-charcoal dark:text-cream mb-2">
                  Country
                </label>
                <input
                  type="text"
                  name="country"
                  value={formData.country}
                  onChange={handleChange}
                  className="w-full px-4 py-3 rounded-xl border border-terracotta/20 dark:border-terracotta/40 bg-white dark:bg-charcoal/50 text-charcoal dark:text-cream placeholder:text-charcoal/40 dark:placeholder:text-cream/40 focus:outline-none focus:border-terracotta dark:focus:border-gold transition-colors"
                />
              </div>
            </div>

            <Button
              type="submit"
              disabled={submitting}
              variant="primary"
              size="lg"
              className="w-full"
              isLoading={submitting}
            >
              {submitting ? "Saving..." : "Save Changes"}
            </Button>
          </form>
        </div>
      </main>
      <Footer />
    </div>
  );
}

"use client";

import { Suspense, useEffect, useState } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { useSession } from "next-auth/react";
import Header from "@/components/Header";
import Footer from "@/components/Footer";
import Button from "@/components/Button";
import { Video, User, List, CreditCard, AlertCircle, CheckCircle } from "lucide-react";

interface Student {
  id: string;
  name: string;
}

interface CompetitionCategory {
  id: string;
  categoryName: string;
  minAge: number;
  maxAge: number;
}

interface Competition {
  id: string;
  title: string;
  entryFeeINR: number;
  bannerUrl?: string | null;
  categories: CompetitionCategory[];
}

// Fallback mock details for simulation
const mockCompetition: Competition = {
  id: "comp-rec-01",
  title: "Borsha Bodhon 2026",
  entryFeeINR: 50.0,
  categories: [
    { id: "cat-1", categoryName: "Bengali Recitation (Ages 4-8)", minAge: 4, maxAge: 8 },
    { id: "cat-2", categoryName: "Bengali Recitation (Ages 9-14)", minAge: 9, maxAge: 14 },
    { id: "cat-3", categoryName: "Singing (Rabindra Sangeet)", minAge: 6, maxAge: 18 }
  ]
};

const mockStudents: Student[] = [
  { id: "s1", name: "Bhaskar Chattopadhyay" },
  { id: "s2", name: "Pooja Chattopadhyay" }
];

function RegisterEntryForm() {
  const { status: sessionStatus } = useSession();
  const router = useRouter();
  const searchParams = useSearchParams();
  const competitionId = searchParams.get("competitionId");

  const [loading, setLoading] = useState(true);
  const [students, setStudents] = useState<Student[]>([]);
  const [competition, setCompetition] = useState<Competition | null>(null);
  
  // Form states
  const [selectedStudent, setSelectedStudent] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("");
  const [fbUrl, setFbUrl] = useState("");
  
  // Feedback states
  const [error, setError] = useState("");
  const [success, setSuccess] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [isUsingMock, setIsUsingMock] = useState(false);
  const [checkoutDetails, setCheckoutDetails] = useState<{ orderId: string; registrationId: string; amount: number } | null>(null);


  const loadRegistrationData = useCallback(async () => {
    setLoading(true);
    try {
      const studentsRes = await fetch("/api/parent/dashboard");
      const dashboardData = await studentsRes.json();
      
      if (!studentsRes.ok) throw new Error(dashboardData.error || "Failed to load details");
      
      setStudents(dashboardData.students);

      // Fetch competition from database if ID is provided
      if (competitionId) {
        const compRes = await fetch(`/api/competitions?id=${competitionId}`);
        const compData = await compRes.json();
        if (compRes.ok) {
          setCompetition(compData);
          setIsUsingMock(false);
        } else {
          throw new Error(compData.error || "Failed to load competition details");
        }
      } else {
        setCompetition(mockCompetition);
        setIsUsingMock(true);
      }
    } catch (err) {
      console.warn("Loading mock data fallback. Database connection could be unconfigured.", err);
      setStudents(mockStudents);
      setCompetition(mockCompetition);
      setIsUsingMock(true);
    } finally {
      setLoading(false);
    }
  }, [competitionId]);

  useEffect(() => {
    if (sessionStatus === "unauthenticated") {
      router.push(`/login?callbackUrl=/register-entry?competitionId=${competitionId}`);
    } else if (sessionStatus === "authenticated") {
      const timer = setTimeout(() => {
        loadRegistrationData();
      }, 0);
      return () => clearTimeout(timer);
    }
  }, [sessionStatus, competitionId, loadRegistrationData, router]);

  const validateFacebookUrl = (url: string) => {
    const fbRegex = /^(https?:\/\/)?(www\.)?(facebook\.com|fb\.watch|fb\.gg)\/.+$/i;
    return fbRegex.test(url);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSubmitting(true);

    if (!selectedStudent) {
      setError("Please select a student profile");
      setSubmitting(false);
      return;
    }
    if (!selectedCategory) {
      setError("Please select a competition category");
      setSubmitting(false);
      return;
    }
    if (!fbUrl) {
      setError("Please paste the Facebook video URL");
      setSubmitting(false);
      return;
    }

    if (!validateFacebookUrl(fbUrl)) {
      setError("Invalid link structure. Make sure you copy a valid Facebook post or video URL.");
      setSubmitting(false);
      return;
    }

    if (isUsingMock) {
      setTimeout(() => {
        setSuccess(true);
        setSubmitting(false);
      }, 1500);
      return;
    }

    try {
      const res = await fetch("/api/registrations/create", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          studentId: selectedStudent,
          competitionCategoryId: selectedCategory,
          fbPostUrl: fbUrl
        })
      });

      const data = await res.json();

      if (!res.ok) {
        setError(data.error || "Failed to initiate registration");
        setSubmitting(false);
      } else {
        triggerRazorpay(data.orderId, data.registrationId, data.amount);
      }
    } catch (err) {
      console.error(err);
      setError("Server connection issue. Failed to connect.");
      setSubmitting(false);
    }
  };

  const handlePaymentSuccess = async () => {
    if (!checkoutDetails) return;
    setError("");
    setSubmitting(true);
    const orderId = checkoutDetails.orderId;
    setCheckoutDetails(null);
    
    try {
      const res = await fetch("/api/registrations/verify", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          razorpayOrderId: orderId,
          razorpayPaymentId: "pay_sim_" + Math.random().toString(36).slice(2, 9),
          razorpaySignature: "sig_sim_" + Math.random().toString(36).slice(2, 9),
        }),
      });

      const data = await res.json();

      if (!res.ok) {
        setError(data.error || "Payment verification failed");
        setSubmitting(false);
      } else {
        setSuccess(true);
        setSubmitting(false);
      }
    } catch (err) {
      console.error(err);
      setError("Network error. Verification failed.");
      setSubmitting(false);
    }
  };

  const handlePaymentFailure = async () => {
    if (!checkoutDetails) return;
    setError("Payment simulation failed or cancelled by user");
    const orderId = checkoutDetails.orderId;
    setCheckoutDetails(null);
    setSubmitting(true);

    try {
      await fetch("/api/registrations/verify", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ razorpayOrderId: orderId }),
      });
    } catch (err) {
      console.error(err);
    } finally {
      setSubmitting(false);
    }
  };

  const triggerRazorpay = (orderId: string, registrationId: string, amount: number) => {
    setCheckoutDetails({ orderId, registrationId, amount });
  };

  if (sessionStatus === "loading" || loading) {
    return (
      <div className="min-h-screen bg-cream dark:bg-charcoal flex flex-col font-sans">
        <div className="flex-1 flex items-center justify-center">
          <div className="w-10 h-10 border-4 border-terracotta dark:border-gold border-t-transparent rounded-full animate-spin" />
        </div>
      </div>
    );
  }

  return (
    <>
      <Header />

      <main className="flex-1 bg-cream dark:bg-charcoal py-16 alpana-pattern">
        <div className="max-w-xl mx-auto px-4 sm:px-6 lg:px-8">
          
          <div className="bg-cream dark:bg-charcoal-light border border-terracotta/10 dark:border-terracotta/20 rounded-2xl shadow-xl relative overflow-hidden flex flex-col">
            
            {/* Top Mini Banner Graphic */}
            <div className="relative w-full h-32 overflow-hidden bg-charcoal/10 border-b border-terracotta/10 dark:border-terracotta/20 shrink-0">
              <img
                src={competition?.bannerUrl || "/images/general.jpg"}
                alt=""
                className="w-full h-full object-cover filter brightness-[0.75] dark:brightness-[0.55]"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/45 via-transparent to-transparent pointer-events-none" />
            </div>

            <div className="p-5 sm:p-8">
              {success ? (
                <div className="text-center space-y-6 py-6">
                  <div className="w-16 h-16 rounded-full bg-green-500/10 text-green-600 flex items-center justify-center mx-auto shadow-md">
                    <CheckCircle className="w-10 h-10" />
                  </div>
                  
                  <div className="space-y-2">
                    <h2 className="font-serif text-2xl font-bold text-charcoal dark:text-cream">Registration Success!</h2>
                    <p className="font-sans text-sm text-charcoal/70 dark:text-cream/70 max-w-sm mx-auto leading-relaxed">
                      Your entry has been registered successfully. We have queued your Facebook video for examiner evaluation.
                    </p>
                  </div>

                  <div className="pt-6 border-t border-terracotta/5 flex flex-col gap-3">
                    <Button
                      onClick={() => router.push("/parent/dashboard")}
                      variant="primary"
                      size="md"
                      className="w-full"
                    >
                      Go to Parent Dashboard
                    </Button>
                    <Button
                      onClick={() => {
                        setSuccess(false);
                        setFbUrl("");
                      }}
                      variant="outline"
                      size="md"
                      className="w-full"
                    >
                      Register Another Entry
                    </Button>
                  </div>
                </div>
              ) : (
                <>
                  <div className="text-center space-y-2 mb-8">
                    <h1 className="font-serif text-3xl font-bold text-charcoal dark:text-cream">
