                      <span className="font-serif text-xl font-bold text-terracotta dark:text-gold">₹{competition?.entryFeeINR}.00</span>
                    </div>

                    <Button
                      type="submit"
                      disabled={submitting || students.length === 0}
                      variant="primary"
                      size="lg"
                      className="w-full"
                      isLoading={submitting}
                    >
                      {submitting ? (
