import prisma from "@/lib/db";
import Link from "next/link";
import QRCode from "qrcode";
import Button from "@/components/Button";
import { CheckCircle, Printer, ShieldAlert, Award } from "lucide-react";

// Dynamic route data fetching
async function getCertificateDetails(certId: string) {
  try {
    const certificate = await prisma.certificate.findUnique({
      where: { certificateId: certId },
      include: {
        registration: {
          include: {
            student: true,
            competitionCategory: {
              include: {
                competition: true,
                category: true,
              },
            },
          },
        },
      },
    });
    return certificate;
  } catch (error) {
    console.warn("DB check failed for certificate, using sandbox mock fallback:", error);
    return null;
  }
}

// Fallback mock details for demonstration
const mockCertificateData = {
  certificateId: "CERT-PP-9901-2940",
  type: "MERIT_1", // 1st Place
  issuedAt: new Date("2026-05-24"),
  registration: {
    registrationId: "PP-2026-REC-0021",
    student: {
      name: "Bhaskar Chattopadhyay",
    },
    competitionCategory: {
      competition: {
        title: "Borsha Bodhon 2026",
      },
      category: {
        name: "Bengali Recitation",
      },
    },
  },
};

interface CertDataDetails {
  certificateId: string;
  type: string;
  issuedAt: Date;
  registration: {
    registrationId: string;
    student: {
      name: string;
    };
    competitionCategory: {
      competition: {
        title: string;
      };
      category: {
        name: string;
      };
    };
  };
}

interface VerifyPageProps {
  params: Promise<{ certificateId: string }>;
}

export default async function VerifyCertificatePage({ params }: VerifyPageProps) {
  const { certificateId } = await params;
  const certIdDecoded = decodeURIComponent(certificateId);

  // 1. Fetch certificate from database
  let certData: CertDataDetails | null = (await getCertificateDetails(certIdDecoded)) as unknown as CertDataDetails | null;
  let isDemo = false;

  // 2. Fall back to mock if not found in DB
  if (!certData) {
    if (certIdDecoded === "CERT-PP-9901-2940" || certIdDecoded.startsWith("CERT-")) {
      certData = mockCertificateData;
      isDemo = true;
    }
  }

  // 3. Generate QR code
  let qrCodeDataUrl = "";
  if (certData) {
    try {
      const origin = process.env.NEXT_PUBLIC_API_URL || `http://localhost:3000`;
      const verifyUrl = `${origin}/verify/${encodeURIComponent(certData.certificateId)}`;
      qrCodeDataUrl = await QRCode.toDataURL(verifyUrl, { margin: 1, width: 120 });
    } catch (qrErr) {
      console.error("Failed to generate QR code:", qrErr);
    }
  }

  const formatDate = (date: Date) => {
    return new Date(date).toLocaleDateString("en-IN", {
      day: "2-digit",
      month: "long",
      year: "numeric",
    });
  };

  const getAwardTitle = (type: string) => {
    switch (type) {
      case "MERIT_1":
        return "Certificate of Merit - 1st Place";
      case "MERIT_2":
        return "Certificate of Merit - 2nd Place";
      case "MERIT_3":
        return "Certificate of Merit - 3rd Place";
      case "SPECIAL_MENTION":
        return "Special Mention Certificate";
      default:
        return "Certificate of Participation";
    }
  };

  return (
    <div className="min-h-screen bg-cream flex flex-col font-sans">
      
      {/* Verification Header Status Panel (Hidden when printing) */}
      <div className="bg-charcoal text-cream-dark py-4 px-6 print:hidden">
        <div className="max-w-7xl mx-auto flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3">
            <Link href="/" className="flex items-center gap-2 text-gold hover:underline">
              <Award className="w-5 h-5" />
              <span className="font-serif font-bold text-sm tracking-wide">প্রতিভা परिषद</span>
            </Link>
            <span className="text-cream/30">|</span>
            {certData ? (
              <span className="flex items-center gap-1 text-green-400 text-xs font-bold">
                <CheckCircle className="w-4 h-4" /> Authenticity Verified Online
              </span>
            ) : (
              <span className="flex items-center gap-1 text-red-400 text-xs font-bold">
                <ShieldAlert className="w-4 h-4" /> Unverified Serial Number
              </span>
            )}
          </div>
 
          {certData && (
            <div className="flex gap-4">
              {isDemo && (
                <span className="text-[10px] bg-yellow-500/20 text-yellow-300 font-bold px-2 py-1 rounded">
                  DEMO RECORD
                </span>
              )}
              <Button
                onClick={() => window.print()}
                variant="primary"
                size="sm"
                className="flex items-center gap-1.5"
              >
                <Printer className="w-3.5 h-3.5" /> Print / Save PDF
              </Button>
            </div>
          )}
        </div>
      </div>
 
      {/* Main Certificate Content */}
      <div className="flex-1 flex items-center justify-center p-4 sm:p-8 md:p-12">
        {!certData ? (
          <div className="max-w-md w-full bg-cream border border-terracotta/20 rounded-2xl p-8 text-center space-y-6 shadow-xl">
            <ShieldAlert className="w-16 h-16 text-terracotta mx-auto animate-bounce" />
            <div className="space-y-2">
              <h1 className="font-serif text-2xl font-bold text-charcoal">Invalid Certificate ID</h1>
              <p className="font-sans text-sm text-charcoal/70 leading-relaxed">
                The certificate serial number <strong>&quot;{certificateId}&quot;</strong> does not match any official credentials issued by the council database.
              </p>
            </div>
            <Link
              href="/"
              className="inline-flex w-full justify-center py-3 bg-charcoal text-cream font-bold rounded-xl text-sm"
            >
              Back to Homepage
            </Link>
          </div>
        ) : (
          /* High-Fidelity Printable Traditional Certificate Frame */
          <div className="max-w-4xl w-full bg-cream border-[16px] border-double border-terracotta rounded-lg p-8 sm:p-16 relative shadow-2xl overflow-hidden print:border-[10px] print:shadow-none print:my-0">
            {/* Traditional Corner Accents using background-image details or decorative elements */}
            <div className="absolute top-2 left-2 w-10 h-10 border-t-2 border-l-2 border-gold-dark" />
            <div className="absolute top-2 right-2 w-10 h-10 border-t-2 border-r-2 border-gold-dark" />
            <div className="absolute bottom-2 left-2 w-10 h-10 border-b-2 border-l-2 border-gold-dark" />
            <div className="absolute bottom-2 right-2 w-10 h-10 border-b-2 border-r-2 border-gold-dark" />

            <div className="flex flex-col items-center text-center space-y-6">
              
              {/* Emblem Logo */}
              <div className="w-16 h-16 rounded-full bg-terracotta text-gold flex items-center justify-center shadow-md">
                <Award className="w-9 h-9" />
              </div>

              {/* Council Title */}
              <div className="space-y-1">
                <h2 className="font-serif text-3xl sm:text-4xl font-bold text-terracotta tracking-wider">
                  प्रतिभा परिषद
                </h2>
                <h3 className="font-sans text-xs sm:text-sm font-bold tracking-widest text-charcoal/80 uppercase">
                  Pratibha Parishad Council for Indian Fine Arts
                </h3>
              </div>

              {/* Award Type Banner */}
              <div className="py-2.5 px-8 bg-gold/10 border-y border-gold/30 w-full max-w-xl">
                <h4 className="font-serif text-xl sm:text-2xl font-semibold text-gold-dark tracking-wide italic">
                  {getAwardTitle(certData.type)}
                </h4>
              </div>

              {/* Certificate Text details */}
              <div className="space-y-4 max-w-2xl text-charcoal leading-relaxed">
                <p className="font-sans text-sm tracking-wide italic">This is to certify that</p>
                <h1 className="font-serif text-2xl sm:text-3xl font-extrabold text-charcoal underline decoration-gold decoration-2 underline-offset-4">
                  {certData.registration.student.name}
                </h1>
                <p className="font-sans text-sm leading-relaxed px-4">
                  has successfully participated in the fine arts division of{" "}
                  <strong>{certData.registration.competitionCategory.category.name}</strong> at the online cultural competition{" "}
                  <strong>{certData.registration.competitionCategory.competition.title}</strong>, earning verified credentials for performance submission under Roll ID{" "}
                  <strong>{certData.registration.registrationId}</strong>.
                </p>
              </div>

              {/* Signatures and QR Verification Block */}
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-8 items-end w-full pt-10 border-t border-terracotta/10 mt-6">
                
                {/* Board signature 1 */}
                <div className="flex flex-col items-center space-y-1">
                  <div className="font-serif text-sm font-bold italic text-charcoal/70">Swapna Sen</div>
                  <div className="w-32 h-[1px] bg-charcoal/20" />
                  <div className="text-[10px] text-charcoal/40 font-bold uppercase">Academic Examiner</div>
                </div>

                {/* QR code verification emblem */}
                <div className="flex flex-col items-center space-y-2">
                  {qrCodeDataUrl && (
                    <img
                      src={qrCodeDataUrl}
                      alt="Verify QR Code"
                      width={100}
                      height={100}
                      className="border border-charcoal/10 rounded p-1"
                    />
                  )}
                  <span className="text-[8px] font-mono text-charcoal/40 font-bold uppercase">
                    ID: {certData.certificateId}
                  </span>
                </div>

                {/* Board signature 2 */}
                <div className="flex flex-col items-center space-y-1">
                  <div className="font-serif text-sm font-bold italic text-charcoal/70">A. Chattopadhyay</div>
                  <div className="w-32 h-[1px] bg-charcoal/20" />
                  <div className="text-[10px] text-charcoal/40 font-bold uppercase">Registrar of Council</div>
                </div>

              </div>

              {/* Date Issued */}
              <div className="text-[10px] text-charcoal/40 font-sans font-semibold uppercase tracking-wider">
                Issued on: {formatDate(certData.issuedAt)}
              </div>

            </div>
          </div>
        )}
      </div>

    </div>
  );
}

"use client";

import Button from "@/components/Button";

export interface Competition {
  id: string;
  title: string;
  entryFeeINR: number;
  registrationDeadline: string;
  categories: string;
  bannerUrl?: string;
  isActive?: boolean;
  scope?: "STATE" | "NATIONAL";
}

interface CompetitionsTabProps {
  competitionsList: Competition[];
  competitionsPage: number;
  setCompetitionsPage: React.Dispatch<React.SetStateAction<number>>;
  itemsPerPage: number;
  setShowCreateModal: (show: boolean) => void;
  navigateToTab: (tab: string) => void;
  setSearch: (search: string) => void;
}

export default function CompetitionsTab({
  competitionsList,
  competitionsPage,
  setCompetitionsPage,
  itemsPerPage,
  setShowCreateModal,
  navigateToTab,
  setSearch,
}: CompetitionsTabProps) {
  return (
    <div className="space-y-6">
      <div className="bg-charcoal-light border border-terracotta/15 rounded-2xl p-6 space-y-6">
        <div className="flex justify-between items-center">
          <div>
            <h3 className="font-serif text-base font-bold">Active Circuits</h3>
            <p className="text-[11px] text-cream/50">Manage deadlines, fees, and category mappings for standard boards.</p>
          </div>
          <Button
            onClick={() => setShowCreateModal(true)}
            variant="primary"
            size="md"
            className="text-[10px]"
          >
            + Add New Circuit
          </Button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {competitionsList && competitionsList.length > 0 ? (
            competitionsList
              .slice((competitionsPage - 1) * itemsPerPage, competitionsPage * itemsPerPage)
              .map((comp: Competition) => (
                <div
                  key={comp.id}
                  onClick={() => {
                    navigateToTab("participants");
                    setSearch(comp.title);
                  }}
                  className="bg-charcoal border border-terracotta/10 rounded-xl p-5 space-y-3 cursor-pointer hover:border-terracotta/40 hover:bg-charcoal-light transition-all select-none overflow-hidden"
                  role="button"
                  tabIndex={0}
                  onKeyDown={(e) => {
                    if (e.key === "Enter" || e.key === " ") {
                      navigateToTab("participants");
                      setSearch(comp.title);
                    }
                  }}
                >
                  {/* Image Thumbnail */}
                  <div className="relative w-full h-24 rounded-lg overflow-hidden bg-charcoal-light border border-terracotta/5 shadow-sm shrink-0">
                    <img
                      src={comp.bannerUrl || "https://images.unsplash.com/photo-1501386761578-eac5c94b800a?w=800&q=80"}
                      alt=""
                      className="w-full h-full object-cover"
                      loading="lazy"
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-charcoal/80 via-charcoal/20 to-transparent pointer-events-none" />
                    <div className="absolute bottom-2 left-2 flex gap-1 items-center">
                      <span className={`px-2 py-0.5 rounded text-[8px] font-bold uppercase ${
                        comp.isActive ? "bg-green-500/90 text-white" : "bg-red-500/90 text-white"
                      }`}>{comp.isActive ? "Active" : "Closed"}</span>
                      <span className={`px-2 py-0.5 rounded text-[8px] font-bold uppercase bg-charcoal/90 text-gold-dark dark:text-gold border border-gold/20`}>
                        {comp.scope === "NATIONAL" ? "National" : "State"}
                      </span>
                    </div>
                  </div>

                  <div className="flex justify-between items-center pt-1">
                    <h4 className="font-serif text-sm font-bold text-cream line-clamp-1">{comp.title}</h4>
                    <span className="text-xs font-bold text-gold shrink-0">₹{comp.entryFeeINR}</span>
                  </div>
                  <div className="text-[10px] text-cream/50 space-y-1">
                    <p>Closing: {new Date(comp.registrationDeadline).toLocaleDateString()}</p>
                    <p className="line-clamp-1">Segments: {comp.categories}</p>
                  </div>
                </div>
              ))
          ) : (
            <p className="text-xs text-cream/50 col-span-3">No active circuits available.</p>
          )}
        </div>

        {competitionsList && competitionsList.length > itemsPerPage && (
          <div className="flex items-center justify-between pt-4 border-t border-terracotta/10">
            <div className="text-xs text-cream/60 font-sans">
              Showing {(competitionsPage - 1) * itemsPerPage + 1} to{" "}
              {Math.min(competitionsPage * itemsPerPage, competitionsList.length)} of {competitionsList.length} circuits
            </div>
            <div className="flex items-center gap-1.5">
              <Button
                onClick={() => setCompetitionsPage(prev => Math.max(1, prev - 1))}
                disabled={competitionsPage === 1}
                variant="secondary"
                size="md"
              >
                Previous
              </Button>
              {Array.from({ length: Math.ceil(competitionsList.length / itemsPerPage) }, (_, i) => i + 1).map(page => (
                <Button
                  key={page}
                  onClick={() => setCompetitionsPage(page)}
                  variant={page === competitionsPage ? "primary" : "secondary"}
                  size="md"
                >
                  {page}
                </Button>
              ))}
              <Button
                onClick={() => setCompetitionsPage(prev => Math.min(Math.ceil(competitionsList.length / itemsPerPage), prev + 1))}
                disabled={competitionsPage === Math.ceil(competitionsList.length / itemsPerPage)}
                variant="secondary"
                size="md"
              >
                Next
              </Button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { Download, Share2, CheckCircle2, Award, Sparkles } from "lucide-react";
import { useState } from "react";
import Button from "../Button";

interface CertificateInfo {
  studentName: string;
  certificateType: "PARTICIPATION" | "MERIT_1" | "MERIT_2" | "MERIT_3" | "SPECIAL_MENTION";
  finalRank?: number;
  categoryName: string;
  certificateUrl: string;
  qrCodeUrl: string;
  competitionTitle: string;
  issueDate: string;
}

interface CertificateDownloadProps {
  certificates: CertificateInfo[];
  competitionTitle: string;
  isParticipantLoggedIn?: boolean;
}

export default function CertificateDownload({
  certificates,
  competitionTitle,
  isParticipantLoggedIn = false,
}: CertificateDownloadProps) {
  const [copiedLink, setCopiedLink] = useState<string | null>(null);

  const handleCopy = (certificateUrl: string) => {
    const baseUrl = typeof window !== "undefined" ? window.location.origin : "";
    const shareUrl = `${baseUrl}/certificates/${certificateUrl}`;
    navigator.clipboard.writeText(shareUrl);
    setCopiedLink(certificateUrl);
    setTimeout(() => setCopiedLink(null), 2000);
  };

  const getCertificateTypeLabel = (type: string) => {
    const labels: Record<string, string> = {
      PARTICIPATION: "Participation Certificate",
      MERIT_1: "Merit Certificate - 1st Place",
      MERIT_2: "Merit Certificate - 2nd Place",
      MERIT_3: "Merit Certificate - 3rd Place",
      SPECIAL_MENTION: "Special Mention Certificate",
    };
    return labels[type] || "Certificate";
  };

  const getCertificateColor = (type: string) => {
    if (type.includes("MERIT_1")) return "border-gold/20 bg-gold/5";
    if (type.includes("MERIT_2")) return "border-gold/15 bg-gold/3";
    if (type.includes("MERIT_3")) return "border-gold/10 bg-gold/2";
    return "border-terracotta/10 bg-cream-dark/10 dark:bg-charcoal-light/10";
  };

  return (
    <section className="py-20 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
      <div className="text-center space-y-3 mb-16">
        <div className="inline-flex p-3 bg-gold/10 text-gold rounded-full">
          <Award className="w-6 h-6" />
        </div>
        <h2 className="font-serif text-3xl font-bold text-charcoal dark:text-cream">
          Your Certificates
        </h2>
        <p className="font-sans text-charcoal/70 dark:text-cream/70 text-sm max-w-xl mx-auto">
          Download and share your achievement certificates from {competitionTitle}
        </p>
        <div className="w-12 h-0.5 bg-terracotta dark:bg-gold mx-auto" />
      </div>

      {certificates.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {certificates.map((cert, idx) => (
            <div
              key={idx}
              className={`border rounded-2xl p-6 space-y-4 transition-all hover:shadow-md ${getCertificateColor(
                cert.certificateType
              )}`}
            >
              {/* Header */}
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1">
                  <h3 className="font-serif text-lg font-bold text-charcoal dark:text-cream">
                    {getCertificateTypeLabel(cert.certificateType)}
                  </h3>
                  <p className="font-sans text-xs text-charcoal/60 dark:text-cream/60 mt-1">
                    {cert.categoryName}
                  </p>
                </div>
                {cert.finalRank && (
                  <div className="px-3 py-1.5 bg-gold/15 rounded-full text-center">
                    <p className="font-serif font-bold text-gold text-sm">
                      Rank #{cert.finalRank}
                    </p>
                  </div>
                )}
              </div>

              {/* Certificate Preview */}
              <div className="relative bg-cream dark:bg-charcoal border border-terracotta/10 rounded-lg overflow-hidden aspect-video">
                <img
                  src={cert.certificateUrl}
                  alt="Certificate preview"
                  className="w-full h-full object-cover"
                />
                <div className="absolute inset-0 bg-gradient-to-b from-transparent via-transparent to-black/20 opacity-0 hover:opacity-100 transition-opacity flex items-center justify-center gap-3">
                  <CheckCircle2 className="w-5 h-5 text-gold animate-pulse" />
                </div>
              </div>

              {/* Details */}
              <div className="grid grid-cols-2 gap-3 border-t border-terracotta/10 pt-3 text-xs">
                <div>
                  <p className="text-charcoal/50 dark:text-cream/50 font-bold uppercase">
                    Issued Date
                  </p>
                  <p className="text-charcoal dark:text-cream font-semibold mt-1">
                    {new Date(cert.issueDate).toLocaleDateString("en-IN", {
                      year: "numeric",
                      month: "short",
                      day: "numeric",
                    })}
                  </p>
                </div>
                <div>
                  <p className="text-charcoal/50 dark:text-cream/50 font-bold uppercase">
                    Certificate ID
                  </p>
                  <p className="text-charcoal dark:text-cream font-mono text-[10px] mt-1 truncate">
                    {cert.certificateUrl.slice(-8).toUpperCase()}
                  </p>
                </div>
              </div>

              {/* Actions */}
              <div className="flex gap-3 pt-2">
                <Button
                  onClick={() => {
                    const link = document.createElement('a');
                    link.href = cert.certificateUrl;
                    link.setAttribute('download', '');
                    document.body.appendChild(link);
                    link.click();
                    document.body.removeChild(link);
                  }}
                  variant="primary"
                  size="md"
                  className="flex-1"
                >
                  <Download className="w-4 h-4" />
                  Download
                </Button>
                <Button
                  onClick={() => handleCopy(cert.certificateUrl)}
                  variant={copiedLink === cert.certificateUrl ? "secondary" : "outline"}
                  size="md"
                  className={`flex-1 ${copiedLink === cert.certificateUrl ? "bg-green-500/20 border-green-500 text-green-700 dark:text-green-300" : ""}`}
                >
                  <Share2 className="w-4 h-4" />
                  {copiedLink === cert.certificateUrl ? "Copied!" : "Share"}
                </Button>
              </div>

              {/* LinkedIn Share Tip */}
              <div className="bg-charcoal/5 dark:bg-cream/5 rounded-lg p-3 border border-charcoal/10 dark:border-cream/10">
                <div className="flex gap-2">
                  <Sparkles className="w-4 h-4 text-gold shrink-0 mt-0.5" />
                  <p className="font-sans text-[10px] text-charcoal/70 dark:text-cream/70 leading-relaxed">
                    Tip: Share your certificate on LinkedIn to showcase your talent and
                    achievement to your professional network.
                  </p>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : isParticipantLoggedIn ? (
        <div className="text-center py-12 bg-cream-dark/10 dark:bg-charcoal-light/10 rounded-xl border border-terracotta/5">
          <Award className="w-12 h-12 text-terracotta/40 dark:text-gold/40 mx-auto mb-3" />
          <p className="font-sans text-charcoal/70 dark:text-cream/70">
            Certificates will be available once judging is complete and results are published.
          </p>
        </div>
      ) : (
        <div className="text-center py-12 bg-terracotta/5 dark:bg-gold/5 rounded-xl border border-terracotta/10 dark:border-gold/10">
          <Award className="w-12 h-12 text-terracotta dark:text-gold mx-auto mb-3" />
          <p className="font-sans text-charcoal dark:text-cream font-semibold mb-2">
            Login to View Your Certificates
          </p>
          <p className="font-sans text-sm text-charcoal/70 dark:text-cream/70 mb-4">
            Sign in with your parent account to access and download your child&apos;s achievement
            certificates.
          </p>
          <Button variant="primary">
            Sign In Now
          </Button>
        </div>
      )}
    </section>
  );
}
